# Phase 1: Analyze the Fix

This is a patch for fixing miscompilation bugs in InstCombine, ValueTracking: 

commit 77eb05683082dd3751ccfab963f5160f1852058d
Author: Nikita Popov <npopov@redhat.com>
Date:   Mon Jul 1 09:26:01 2024 +0200

    [InstCombine] Simplify select using KnownBits of condition (#95923)

    Simplify the arms of a select based on the KnownBits implied by its condition.
    For now this only handles the case where the select arm folds to a constant,
    but this can be generalized to handle other patterns by using
    SimplifyDemandedBits instead (in that case we would also have to limit to
    non-undef conditions).

    This is implemented by adding a new member to SimplifyQuery that can be used
    to inject an additional condition. The affected values are pre-computed and
    we don't call computeKnownBits() if the select arms don't contain affected
    values. This reduces the cost in some pathological cases.

diff --git a/llvm/include/llvm/Analysis/SimplifyQuery.h b/llvm/include/llvm/Analysis/SimplifyQuery.h
index 25b8f9b5eaf1..a560744f0122 100644
--- a/llvm/include/llvm/Analysis/SimplifyQuery.h
+++ b/llvm/include/llvm/Analysis/SimplifyQuery.h
@@ -9,6 +9,7 @@
 #ifndef LLVM_ANALYSIS_SIMPLIFYQUERY_H
 #define LLVM_ANALYSIS_SIMPLIFYQUERY_H

+#include "llvm/ADT/SmallPtrSet.h"
 #include "llvm/IR/Operator.h"

 namespace llvm {
@@ -57,6 +58,15 @@ struct InstrInfoQuery {
   }
 };

+/// Evaluate query assuming this condition holds.
+struct CondContext {
+  Value *Cond;
+  bool Invert = false;
+  SmallPtrSet<Value *, 4> AffectedValues;
+
+  CondContext(Value *Cond) : Cond(Cond) {}
+};
+
 struct SimplifyQuery {
   const DataLayout &DL;
   const TargetLibraryInfo *TLI = nullptr;
@@ -64,6 +74,7 @@ struct SimplifyQuery {
   AssumptionCache *AC = nullptr;
   const Instruction *CxtI = nullptr;
   const DomConditionCache *DC = nullptr;
+  const CondContext *CC = nullptr;

   // Wrapper to query additional information for instructions like metadata or
   // keywords like nsw, which provides conservative results if those cannot
@@ -113,6 +124,12 @@ struct SimplifyQuery {
     Copy.DC = nullptr;
     return Copy;
   }
+
+  SimplifyQuery getWithCondContext(const CondContext &CC) const {
+    SimplifyQuery Copy(*this);
+    Copy.CC = &CC;
+    return Copy;
+  }
 };

 } // end namespace llvm
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 7deb7bd4e312..c0d49ca99c1a 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -771,6 +771,10 @@ static void computeKnownBitsFromCond(const Value *V, Value *Cond,

 void llvm::computeKnownBitsFromContext(const Value *V, KnownBits &Known,
                                        unsigned Depth, const SimplifyQuery &Q) {
+  // Handle injected condition.
+  if (Q.CC && Q.CC->AffectedValues.contains(V))
+    computeKnownBitsFromCond(V, Q.CC->Cond, Known, Depth, Q, Q.CC->Invert);
+
   if (!Q.CxtI)
     return;

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index aff691b00041..979495dae853 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3519,6 +3519,33 @@ static bool matchFMulByZeroIfResultEqZero(InstCombinerImpl &IC, Value *Cmp0,
   return false;
 }

+/// Check whether the KnownBits of a select arm may be affected by the
+/// select condition.
+static bool hasAffectedValue(Value *V, SmallPtrSetImpl<Value *> &Affected,
+                             unsigned Depth) {
+  if (Depth == MaxAnalysisRecursionDepth)
+    return false;
+
+  // Ignore the case where the select arm itself is affected. These cases
+  // are handled more efficiently by other optimizations.
+  if (Depth != 0 && Affected.contains(V))
+    return true;
+
+  if (auto *I = dyn_cast<Instruction>(V)) {
+    if (isa<PHINode>(I)) {
+      if (Depth == MaxAnalysisRecursionDepth - 1)
+        return false;
+      Depth = MaxAnalysisRecursionDepth - 2;
+    }
+    return any_of(I->operands(), [&](Value *Op) {
+      return Op->getType()->isIntOrIntVectorTy() &&
+             hasAffectedValue(Op, Affected, Depth + 1);
+    });
+  }
+
+  return false;
+}
+
 Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -4016,5 +4043,33 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal))
     return BinaryOperator::CreateXor(CondVal, FalseVal);

+  if (SelType->isIntOrIntVectorTy() &&
+      (!isa<Constant>(TrueVal) || !isa<Constant>(FalseVal))) {
+    // Try to simplify select arms based on KnownBits implied by the condition.
+    CondContext CC(CondVal);
+    findValuesAffectedByCondition(CondVal, /*IsAssume=*/false, [&](Value *V) {
+      CC.AffectedValues.insert(V);
+    });
+    SimplifyQuery Q = SQ.getWithInstruction(&SI).getWithCondContext(CC);
+    if (!CC.AffectedValues.empty()) {
+      if (!isa<Constant>(TrueVal) &&
+          hasAffectedValue(TrueVal, CC.AffectedValues, /*Depth=*/0)) {
+        KnownBits Known = llvm::computeKnownBits(TrueVal, /*Depth=*/0, Q);
+        if (Known.isConstant())
+          return replaceOperand(SI, 1,
+                                ConstantInt::get(SelType, Known.getConstant()));
+      }
+
+      CC.Invert = true;
+      if (!isa<Constant>(FalseVal) &&
+          hasAffectedValue(FalseVal, CC.AffectedValues, /*Depth=*/0)) {
+        KnownBits Known = llvm::computeKnownBits(FalseVal, /*Depth=*/0, Q);
+        if (Known.isConstant())
+          return replaceOperand(SI, 2,
+                                ConstantInt::get(SelType, Known.getConstant()));
+      }
+    }
+  }
+
   return nullptr;
 }


## Your Task for Phase 1 ##

Analyze the fix above carefully and identify potential issues, edge cases, or gaps that the fix might miss. According to the analysis, propose test strategies for exposing the issue. These strategies will be used in Phase 2 to mutate existing test cases to target the identified issues.

Please notice that you are analyzing the fix proposed by an expert LLVM developer. So you should pay special attention to the semantics of the fix, especially regarding deep optimization correctness, rather than simple syntax or surface-level issues. 

## Subsystem Knowledge for InstCombine, ValueTracking ##

For reference, here are some key points about the InstCombine, ValueTracking you should consider (but do not limit to these) in your analysis:

# Subsystem Knowledge for InstCombine

## Elements Frequently Missed

*   **Poison-Generating Flags (`nsw`, `nuw`, `exact`, `inbounds`, `disjoint`, `samesign`)**: These flags are frequently retained when instructions are moved, reassociated, or when their guarding conditions (like `select` instructions) are removed. The optimization pass misses that the conditions guaranteeing these flags may no longer hold in the new context, leading to incorrect poison generation.
*   **Fast-Math Flags (`nnan`, `ninf`, `nsz`)**: The pass frequently misses the semantic differences of these flags across different instruction types (e.g., `select` vs. `minnum`/`maxnum` or binary operators). It often blindly copies or propagates these flags from inner to outer operations, or from conditional to unconditional operations, without properly intersecting them.
*   **UB-Implying Attributes (`noundef`, `range`)**: When intrinsics or instructions are relaxed to return `poison` for edge cases, or when their operands are simplified, the pass frequently forgets to drop attributes that escalate `poison` to immediate Undefined Behavior (UB).
*   **NaN Sign Bits and Payloads**: The pass frequently misses the requirement to preserve the sign bit and payload of NaN values. Optimizations like folding conditional negations to `fabs` or simplifying based on demanded floating-point classes often incorrectly overwrite or clear the NaN sign bit.
*   **Undef vs. Poison Semantics**: The pass frequently conflates `undef` and `poison`. It misses that `undef` can evaluate to different values at different use sites (e.g., in masked merges or vector selects) and incorrectly upgrades `undef` to `poison`, or treats `poison` as a safe wildcard (e.g., matching a zero-broadcast mask).
*   **Pointer Provenance**: When simplifying pointer comparisons (e.g., replacing one pointer with another because they compare equal), the pass frequently misses that pointers with the same address can have different provenances, leading to invalid memory access assumptions.
*   **Multi-Use Instruction Contexts**: When performing Known Bits or Demanded Bits analysis, the pass frequently misses checking if an instruction has multiple uses. It erroneously applies context-specific constraints (valid only at one use site) to simplify the root instruction globally.
*   **Non-Power-of-Two Integer Widths**: The pass frequently assumes that bitwise masking tricks (like using `BitWidth - 1` as a mask) work universally, missing the fact that these mathematical equivalences break down for non-power-of-two integer types (e.g., `i33`).
*   **Vector Lane-Crossing Dependencies**: In vector optimizations, the pass frequently misses that lane-crossing operations (like `shufflevector`) break element-wise assumptions. It incorrectly applies scalar known-bits or demanded-elements logic to individual lanes without accounting for cross-lane data movement.

## Patterns Not Well Handled

### Pattern 1: Unconditional Execution of Conditionally Guarded Operations
The optimization pass struggles when converting conditional control flow (like `select` instructions or short-circuiting logical AND/OR) into unconditional sequences (like bitwise AND/OR, `umax`, or direct arithmetic). The core issue is that the original condition acts as a guard against poison-generating flags, UB-implying attributes, or out-of-bounds operands. When the pass folds the pattern, it frequently reuses the original instructions but fails to strip flags like `nsw`, `samesign`, or `range`. Consequently, edge-case inputs that were previously bypassed now unconditionally execute the flagged instructions, propagating `poison` or triggering UB.

### Pattern 2: Invalid Fast-Math Flag Propagation in Floating-Point Folds
High-level floating-point simplifications—such as folding a `select` into a binary operator, converting conditional negations to `fabs`, or commuting truncations with intrinsics—are not well handled regarding Fast-Math Flags (FMF). The pass often takes the union of flags or blindly copies flags from a conditionally executed instruction to an unconditionally executed one. This causes the optimized code to make overly aggressive assumptions (e.g., assuming no infinities or NaNs) on paths where those assumptions are invalid, leading to miscompilations that violate strict IEEE-754 semantics.

### Pattern 3: Context-Leakage in Multi-Use Instruction Simplification
The pass does not well handle the simplification of root instructions that have multiple uses across different basic blocks. When optimizations like Demanded Bits or Known Bits are triggered from a specific use site, the pass may utilize local dominating conditions (e.g., an `icmp` guard or `llvm.assume`). However, it incorrectly applies these local facts to modify the shared root instruction in-place. This leaks context-specific assumptions to all other uses of the instruction, corrupting the data flow for execution paths that do not share those constraints.

### Pattern 4: Unsafe Pointer Arithmetic and Comparison Canonicalization
Patterns involving the reassociation, merging, or comparison of `getelementptr` (GEP) instructions are frequently mishandled when no-wrap guarantees are absent or mixed. For example, the pass attempts to merge GEPs with mixed-sign offsets while retaining the `inbounds` flag, failing to realize that intermediate calculations might temporarily step out of bounds. Similarly, it folds pointer comparisons into direct integer/index comparisons without verifying `nuw`/`nusw` flags or accounting for `inttoptr` truncations, ignoring the fact that pointer arithmetic can wrap around the address space.

### Pattern 5: Mishandling of Poison/Undef in Vector Lane Operations
Vector transformations involving `shufflevector`, vector `select`s, and vector constants are highly prone to bugs when `poison` or `undef` elements are present. The pass often attempts to distribute operations across `select` branches or deduplicate binary operations by matching shuffle masks. However, it fails to handle the propagation of `poison` correctly—such as treating a `poison` lane as a safe `0` for deduplication, or unconditionally propagating a `poison` constant when a guarding vector `select` is removed. Additionally, it incorrectly assumes `undef` conditions in vector selects evaluate to a specific boolean value, leading to overly aggressive dead-code elimination.

### Pattern 6: Speculation and Hoisting of Non-Speculatable Instructions
The pass does not well handle the movement or operand substitution of non-speculatable instructions (like integer division, remainder, or memory loads). Patterns that attempt to sink a division after a `select`, hoist an `extractelement` above a division, or substitute a variable operand with a constant based on a conditional check frequently introduce immediate Undefined Behavior. The pass fails to recognize that the transformation exposes the non-speculatable instruction to `poison` values, out-of-bounds indices, or zero divisors that were safely masked or guarded in the original control flow.
# Subsystem Knowledge for ValueTracking

## Elements Frequently Missed

*   **Poison-Generating Flags on Instructions**: Flags that can generate poison values (such as `samesign`, `nsw`, `nnan`, `ninf`) are frequently overlooked when they are attached directly to instructions like `icmp`, `phi`, or `sub`. The analysis often mistakenly assumes an instruction's result is safe solely because its incoming operands are safe, ignoring the flags.
*   **Mismatched Flags Between Paired Instructions**: When analyzing instruction pairs (e.g., an `fcmp` followed by a `select`), the compiler frequently misses discrepancies in Fast-Math Flags (FMF) or poison-generating flags between the two instructions. It incorrectly applies the relaxed semantics of one instruction to the entire pattern.
*   **IEEE-754 Floating-Point Edge Cases**: Specific floating-point behaviors are frequently missed during value tracking and constant folding, including:
    *   **NaN Dropping Semantics**: Operations like `minnum` and `maxnum` discard NaN operands, meaning the sign bit of a NaN operand does not propagate to the result.
    *   **Signed Zeros**: The distinction between `+0.0` and `-0.0` is ignored during strict vs. non-strict inequality transformations, even when the `nsz` (no signed zeros) flag is absent.
    *   **Division by Negative Zero**: Dividing a positive number by `-0.0` yields `-Inf` (a strictly negative value), which is missed when analyzing the signs of the operands.
    *   **Zero Multiplied by Infinity**: The cross-operand scenario where one operand is `0` and the other is `Inf` results in `NaN`, which is missed if the compiler only checks operands individually.
*   **Poison Elements in Vector Constants**: Partially poisonous vector constants (e.g., `<0, poison>`) are frequently treated as perfectly safe equivalent values (like a pure zero vector) during algebraic simplifications, leading to the unintended introduction of poison into well-defined execution paths.
*   **1-bit Integer Boundary Conditions**: The wrap-around behavior specific to 1-bit integers (`i1`) is missed during constant range calculations. Adding 1 to the maximum value of an `i1` wraps around to the lower bound, erroneously creating an empty range.
*   **Speculative Execution Safety Context**: The implicit properties that make an instruction safe to execute speculatively (e.g., a pointer being non-null, or a divisor being non-zero) are missed when the compiler substitutes operands based on conditional equivalence.

## Patterns Not Well Handled

### Pattern 1: Select-Based Min/Max and Conditional Pattern Matching
The optimization pass struggles to safely transform `select` instructions driven by comparisons (`icmp` or `fcmp`) into higher-level intrinsics like `minnum`, `maxnum`, `smin`, or `smax`. The pattern matching logic frequently fails to respect the strict semantics of the original `select` instruction. It improperly hoists fast-math flags from the comparison to the entire pattern, ignores mismatched signed zeros, and fails to preserve ordered/unordered predicates when NaNs are possible. Furthermore, it fails to recognize that a `select` instruction acts as a "poison shield" (conditionally ignoring poison values from unselected branches), whereas the resulting intrinsics evaluate unconditionally and propagate poison.

### Pattern 2: Poison and Undef Propagation in Control Flow and Simplification
Transformations that simplify control flow, invert logic, or eliminate defensive instructions (like `freeze`) do not handle poison propagation well. The compiler often assumes that if the inputs to an expression tree are well-defined, the output is well-defined. This high-level assumption breaks down when the compiler swaps `select` operands involving partially poisonous vectors, replaces conditional selects with logical `xor` operations without checking for mismatched poison-generating flags, or ignores poison-generating flags on `phi` nodes. These flawed transformations consistently result in optimized code that is "more poisonous" than the original IR.

### Pattern 3: Floating-Point Property Deduction
The compiler's ValueTracking subsystem poorly handles the deduction of floating-point properties (such as sign bits, NaN possibilities, and value ranges) when combining multiple operations. It attempts to apply standard algebraic rules to floating-point arithmetic without adequately accounting for IEEE-754 edge cases. For example, it incorrectly deduces that a multiplication cannot produce `NaN` if neither operand is *always* zero or infinity, missing the case where they dynamically evaluate to zero and infinity simultaneously. Similarly, it incorrectly assumes the result of a division cannot be negative if neither operand is strictly negative, failing to account for division by negative zero.

### Pattern 4: Context-Blind Operand Substitution in Speculative Execution
The optimization pass does not well handle the substitution of variables with constants in speculatively executed instructions. When the compiler identifies that a variable is equivalent to a constant (e.g., `ptr == null`) within a specific conditional branch, it attempts to substitute the constant into instructions that use that variable. However, it performs this substitution blindly on instructions that are executed unconditionally (speculatively) outside the branch. This pattern destroys the very properties (like dereferenceability) that made the speculative execution safe in the first place, immediately introducing Undefined Behavior into the optimized program.

Once you have analyzed the fix and identified potential issues or edge cases, use the `stop` tool to specify the issues you found and proposed test strategies along with detailed reasoning. Follow this structure: 

1. **Fix Understanding**: 
   - What optimization or transformation does this fix enable or correct?
   - What are the key changes made in the patch?

2. **Assumptions Identified**:
   - What assumptions does the fix make about the input?
   - What preconditions must hold for this fix to be correct?

3. **Potential Cases to Break Assumptions**:
For each assumption and precondition identified, describe specific scenarios or input characteristics that could violate them. The potential cases should only focus on the semantics related to the analysis above.

4. **Test Strategies**:
   For each potential issue you identified, propose specific test strategies:
   - **Strategy #1**: [Name]
   - Target: [What to mutate]
   - Rationale: [Why this might expose an issue]
   - Expected Issue: [What incorrect behavior might occur]

   - **Strategy #2**: [Name]
   - Target: [What to mutate]
   - Rationale: [Why this might expose an issue]
   - Expected Issue: [What incorrect behavior might occur]

   [Continue for 3-5 test strategies]

